import{c as e,Q as t,j as r,m as i}from"./chunks/framework.DVkeSyfh.js";const p=JSON.parse('{"title":"Документация dj-track-similarity","description":"","frontmatter":{},"headers":[],"relativePath":"ru/project-guide.md","filePath":"ru/project-guide.md","lastUpdated":1780001723000}'),l={name:"ru/project-guide.md"};function h(d,a,o,m,s,c){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="документация-dj-track-similarity" tabindex="-1">Документация dj-track-similarity <a class="header-anchor" href="#документация-dj-track-similarity" aria-label="Permalink to &quot;Документация dj-track-similarity&quot;">​</a></h1><p>Это индекс документации <code>dj-track-similarity</code>. Начинайте отсюда, если не уверены, какая страница нужна. Краткое введение остается в <a href="https://github.com/MeteorBurn/dj-track-similarity/blob/main/README.md" target="_blank" rel="noreferrer">README репозитория</a>; страницы ниже содержат пользовательские и разработческие справочники.</p><p>Русская локализация переводит текущую пользовательскую документацию. Английская версия остается канонической для регулярных обновлений UI-документации; русская версия обновляется по отдельному запросу.</p><p>Для первого локального запуска прочитайте <a href="./overview.html">Обзор</a>, затем используйте <a href="./cli.html">Справочник CLI</a>, чтобы просканировать папку и запустить сервер. Если база библиотеки уже есть, откройте <a href="./analysis.html">Семейства анализа</a>, чтобы выбрать следующий проход анализа, а затем <a href="./search-and-tags.html">Поиск и запись тегов</a> для ежедневного DJ-рабочего процесса.</p><h2 id="основнои-проект" tabindex="-1">Основной проект <a class="header-anchor" href="#основнои-проект" aria-label="Permalink to &quot;Основной проект&quot;">​</a></h2><ul><li><a href="./overview.html">Обзор</a>: назначение проекта, ключевые возможности, модель безопасности и поддерживаемые аудиофайлы.</li><li><a href="./architecture.html">Архитектура и среда выполнения</a>: карта backend/frontend, зависимости, заметки по CUDA/FFmpeg и логирование. Используйте, когда неясны установка, GPU, декодирование аудио или запуск сервера.</li><li><a href="./database.html">База данных и сохраняемые данные</a>: схема SQLite, метаданные, embeddings и хранилище оценок классификаторов. Используйте, чтобы понять, что приложение сохраняет и что остается только для чтения.</li><li><a href="./analysis.html">Семейства анализа</a>: Sonara, MAEST, MERT, CLAP и оценка продвинутыми классификаторами. Используйте перед долгими задачами анализа, чтобы выбрать нужное семейство признаков.</li><li><a href="./search-and-tags.html">Поиск и запись тегов</a>: рабочие процессы SONARA/MERT/CLAP/CLASS и запись стандартных жанров. Используйте для поиска совместимых треков, фильтрации по классификаторам и решения, когда безопасно записывать жанры.</li><li><a href="./cli.html">Справочник CLI</a>: команды <code>dj-sim</code>, параметры, вывод и примеры.</li><li><a href="./api.html">Справочник Web API</a>: FastAPI endpoints, которые использует frontend.</li><li><a href="./development.html">Разработка и проверка</a>: команды настройки и рекомендации по фокусной проверке.</li></ul><h2 id="rhythm-lab" tabindex="-1">Rhythm Lab <a class="header-anchor" href="#rhythm-lab" aria-label="Permalink to &quot;Rhythm Lab&quot;">​</a></h2><ul><li><a href="./rhythm-lab.html">Rhythm Lab</a>: профили классификаторов, UI разметки, обучение, предсказания, promotion, удаление и интеграция с основным приложением.</li></ul><h2 id="служебные-скрипты" tabindex="-1">Служебные скрипты <a class="header-anchor" href="#служебные-скрипты" aria-label="Permalink to &quot;Служебные скрипты&quot;">​</a></h2><p>Здесь документируются только стабильные пользовательские помощники:</p><ul><li><a href="./scripts/repair-audio-metadata.html">Скрипт восстановления аудиометаданных</a>: диагностика и восстановление метаданных/контейнеров с dry-run по умолчанию.</li><li><a href="./scripts/audio-dedup.html">Скрипт отчета о дублях аудио</a>: только отчетный анализ кандидатов на дубли.</li><li><a href="./scripts/optimize-database.html">Скрипт оптимизации базы данных</a>: проверенная по схеме резервная копия SQLite, vacuum, analyze и integrity check.</li></ul>',11)])])}const u=e(l,[["render",h]]);export{p as __pageData,u as default};
